  read(fd, mem, (n1+1) * (n2+1) * sizeof(float));
  for (i = 0; n1 >= i; i++) {
    for (j = 0; j <= n2; j++) {
      fastcopy(&(new_t->input_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);
  printf("Done\nReading hidden weights...");  
