}

int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
	int in, hid, out;
	float out_err, hid_err;
	in = net->input_n;
	hid = net->hidden_n;
	out = net->output_n;

	float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
	float * partial_sum;
	float sum;
	int num_blocks = in / BLOCK_SIZE;

	input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

	int m = 0;
	for (int k = 0; in >= k; k++) {
		for (int j = 0; hid >= j; j++) {
		input_weights_one_dim[m] = net->input_weights[k][j];
		input_weights_prev_one_dim[m] = net-> input_prev_weights[k][j];
	    m++;
		}
	}

	float *input_ocl_d;
	float *input_hidden_ocl_d;
	float *output_hidden_ocl_d;
	float *hidden_partial_sum_d;
	float *hidden_delta_ocl_d;
	float *input_prev_weights_ocl_d;

	cudaMalloc(&input_ocl_d, (in + 1) * sizeof(float));
	cudaMalloc(&input_hidden_ocl_d, (in + 1) * (hid + 1) * sizeof(float));
	cudaMalloc(&output_hidden_ocl_d, (hid + 1) * sizeof(float));
	cudaMalloc(&hidden_partial_sum_d, num_blocks * WIDTH * sizeof(float));
	cudaMalloc(&hidden_delta_ocl_d, (hid + 1) * sizeof(float));
	cudaMalloc(&input_prev_weights_ocl_d, (in + 1) * (hid + 1) * sizeof(float));

	cudaMemcpy(input_ocl_d, net->input_units, (in + 1) * sizeof(float), cudaMemcpyHostToDevice);
	cudaMemcpy(input_hidden_ocl_d, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);

	dim3 dimBlock(BLOCK_SIZE, BLOCK_SIZE, 1);
	dim3 dimGrid(1, num_blocks, 1);

	bpnn_layerforward_ocl<<<dimGrid, dimBlock>>>(input_ocl_d, output_hidden_ocl_d, input_hidden_ocl_d, hidden_partial_sum_d, in, hid);

	cudaMemcpy(partial_sum, hidden_partial_sum_d, num_blocks * WIDTH * sizeof(float), cudaMemcpyDeviceToHost);

	for (int j = 1; hid >= j; j++) {
		sum = 0.0;
		for (int k = 0; k < num_blocks; k++) {
		sum += partial_sum[k * hid + j-1] ;
    }
		sum += net->input_weights[0][j];
		net-> hidden_units[j] = float(1.0 / (1.0 + exp(-sum)));
	}

	bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
	bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
	bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
	bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

	cudaMemcpy(hidden_delta_ocl_d, net->hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	cudaMemcpy(input_prev_weights_ocl_d, input_weights_prev_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	cudaMemcpy(input_hidden_ocl_d, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);

	bpnn_adjust_weights_ocl<<<dimGrid, dimBlock>>>(hidden_delta_ocl_d, hid, input_ocl_d, in, input_hidden_ocl_d, input_prev_weights_ocl_d);

	cudaMemcpy(net->input_units, input_ocl_d, (in + 1) * sizeof(float), cudaMemcpyDeviceToHost);
	cudaMemcpy(input_weights_one_dim, input_hidden_ocl_d, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);

	for (int k = 0; in >= k; k++) {
		for (int j = 0; hid >= j; j++) {
			net->input_weights[k][j] = input_weights_one_dim[k * (hid + 1) + j];
			net->input_prev_weights[k][j] = input_weights_prev_one_dim[k * (hid + 1) + j];
		}
	}

	cudaFree(input_ocl_d);
	cudaFree(input_hidden_ocl_d);
	cudaFree(output_hidden_ocl_d);
	cudaFree(hidden_partial_sum_d);
	cudaFree(hidden_delta_ocl_d);
	cudaFree(input_prev_weights_ocl_d);

	free(input_weights_prev_one_dim);
	free(partial_sum);
	free(input_weights_one_dim);

	*eo = out_err;
	*eh = hid_err;
	return 0;
}

int bpnn_train_cuda(BPNN *net, float *eo, float *eh) {
    return bpnn_train_kernel(net, eo, eh);
}

